const fs = require('fs');

class FixtureScript {
  constructor(name, ingredient, ctx) {
    this._ingredient = ingredient;
    this._ctx = ctx;
  }

  async Execute() {
    const outputVar = this._ingredient.properties.parameters.get('outputPath');
    const messageVar = this._ingredient.properties.parameters.get('message');

    const outputPath = outputVar ? await outputVar.valueAsync(this._ctx) : '';
    const message = messageVar ? await messageVar.valueAsync(this._ctx) : '';

    fs.writeFileSync(outputPath, `ok:${message}`);
  }
}

module.exports = {
  pluginNS: '@azbake/fixture-script',
  plugin: FixtureScript
};